<?php namespace App\Domains\RealEstateRental\Services; class RentalService { public function createResidential(array $data) { return \App\Domains\RealEstateRental\Models\ResidentialRental::create($data); } public function createCommercial(array $data) { return \App\Domains\RealEstateRental\Models\CommercialRental::create($data); } public function createLand(array $data) { return \App\Domains\RealEstateRental\Models\LandRental::create($data); } public function createEnterprise(array $data) { return \App\Domains\RealEstateRental\Models\EnterpriseRental::create($data); } }
